package unit.qa;

import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.NullAndEmptySource;
import org.junit.jupiter.params.provider.ValueSource;
import persistence.model.QA;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

class AnswerTest {

    // ------------------------------ Positive values ------------------------------

    @ParameterizedTest
    @DisplayName("Answer should accept valid lengths.")
    @ValueSource(strings = {
            "A",
            "AA",
            "AAAAAAAAAAAAAAAAAAAAAAAAA",
            "",
            "",
            "https://example.com/help",
            "Line one\nLine two"
    })
    void answerShouldAcceptValidLengths(String answer) {
        // When
        QA subject = new QA();
        subject.setAnswer(answer);

        // Then
        assertThat(subject.getAnswer()).isEqualTo(answer).isNotBlank().hasSizeBetween(1, 1000);
        assertThat(subject.getAnswer() != null
                && !subject.getAnswer().isBlank()
                && subject.getAnswer().length() >= 1
                && subject.getAnswer().length() <= 1000).isTrue();
    }

    // ------------------------------ Negative values ------------------------------

    @ParameterizedTest
    @DisplayName("Answer should reject invalid lengths.")
    @ValueSource(strings = {
            "",
            "",
            "",
            ""
    })
    void answerShouldRejectInvalidLengths(String answer) {
        // Given
        QA subject = new QA();

        // Then
        assertThatThrownBy(() -> subject.setAnswer(answer))
                .isInstanceOf(IllegalArgumentException.class);
    }

    // ------------------------------ Edge cases ------------------------------

    @ParameterizedTest
    @DisplayName("Answer should reject null, empty, and blank values.")
    @NullAndEmptySource
    @ValueSource(strings = {
            " "
    })
    void answerShouldRejectNullEmptyAndBlankValues(String answer) {
        // Given
        QA subject = new QA();

        // Then
        assertThatThrownBy(() -> subject.setAnswer(answer))
                .isInstanceOf(IllegalArgumentException.class);
    }

}
